// We'll use the MutationObserver API to detect when popups are added or removed from the DOM

// Function to prevent background scrolling
const preventBackgroundScroll = () => {
  // Check if any popup is currently open
  const openPopups = document.querySelectorAll('.ww-popup-wrapper');
  
  if (openPopups.length > 0) {
    // If at least one popup is open, prevent background scrolling
    document.body.style.overflow = 'hidden';
  } else {
    // If no popups are open, allow background scrolling
    document.body.style.overflow = '';
  }
};

// Create a MutationObserver to watch for changes to the DOM
const observer = new MutationObserver((mutations) => {
  for (const mutation of mutations) {
    if (mutation.type === 'childList') {
      // Check if popups were added or removed
      const addedNodes = Array.from(mutation.addedNodes);
      const removedNodes = Array.from(mutation.removedNodes);
      
      const popupAdded = addedNodes.some(node => 
        node.nodeType === 1 && node.classList && node.classList.contains('ww-popup-wrapper')
      );
      
      const popupRemoved = removedNodes.some(node => 
        node.nodeType === 1 && node.classList && node.classList.contains('ww-popup-wrapper')
      );
      
      if (popupAdded || popupRemoved) {
        // If a popup was added or removed, update the scroll behavior
        preventBackgroundScroll();
      }
    }
  }
});

// Start observing the document body for changes
observer.observe(document.body, { childList: true, subtree: true });

// Initial check in case a popup is already open
